print("\nAll business IDs found:")
for biz in businesses:
    print(f"  {biz['business_id']}")

# Show all descriptions to understand full scope
print("\nAll descriptions:")
for biz in businesses:
    print(f"\n{biz['business_id']}:")
    print(f"  {biz.get('description', 'No description')[:300]}")

# Now map business_ref to categories properly
biz_to_cats = {}
for biz in businesses:
    biz_ref = biz['business_id'].replace('businessid_', 'businessref_')
    desc = biz.get('description', '')

    cats = []
    if desc:
        desc_lower = desc.lower()

        # Try to extract service categories
        if 'services in' in desc_lower:
            service_part = desc_lower.split('services in')[1].split('.')[0]
            items = re.split(r',|\band\b', service_part)
        elif 'including' in desc_lower:
            service_part = desc_lower.split('including')[1].split('.')[0]
            items = re.split(r',|\band\b', service_part)
        elif 'offers' in desc_lower:
            service_part = desc_lower.split('offers')[1].split('.')[0]
            items = re.split(r',|\band\b', service_part)
        else:
            items = []

        for item in items:
            cat = item.strip().rstrip('.,').strip()
            # Clean up common phrases
            if cat.startswith('a range of'):
                cat = cat.replace('a range of', '').strip()
            if cat.startswith('range of'):
                cat = cat.replace('range of', '').strip()

            if cat and 2 < len(cat) < 100:
                cat = cat.title()
                cats.append(cat)

    biz_to_cats[biz_ref] = cats

print(f"\nMapped {len(biz_to_cats)} businesses to categories")

