from collections import Counter

# Load all the business data
all_businesses = locals()['var_functions.query_db:42']
print("Loading businesses...")
biz_to_cats = {}
for biz in all_businesses:
    biz_ref = biz['business_id'].replace('businessid_', 'businessref_')
    desc = biz.get('description', '')

    cats = []
    if desc:
        desc_lower = desc.lower()

        # Extract category part after services/including
        if 'services in' in desc_lower:
            parts = desc_lower.split('services in')
            if len(parts) > 1:
                service_text = parts[1].split('.')[0]
                items = re.split(r',|\band\b', service_text)
                for item in items:
                    cat = item.strip().rstrip('.,').strip()
                    if cat: cats.append(cat.title())

        elif 'including' in desc_lower:
            parts = desc_lower.split('including')
            if len(parts) > 1:
                service_text = parts[1].split('.')[0]
                items = re.split(r',|\band\b', service_text)
                for item in items:
                    cat = item.strip().rstrip('.,').strip()
                    if cat: cats.append(cat.title())

    biz_to_cats[biz_ref] = cats

print(f"Mapped {len(biz_to_cats)} businesses")

# Load all reviews
reviews_path = locals()['var_functions.query_db:6']
with open(reviews_path) as f:
    all_reviews = json.load(f)

print(f"Loaded {len(all_reviews)} reviews from 2016 users")

# Count reviews by category
total_counts = Counter()
matched = 0
for review in all_reviews:
    biz_ref = review.get('business_ref', '')
    if biz_ref in biz_to_cats and biz_to_cats[biz_ref]:
        for cat in biz_to_cats[biz_ref]:
            if cat:
                total_counts[cat] += 1
        matched += 1

print(f"Matched {matched} reviews to categorized businesses")
print(f"Found {len(total_counts)} unique categories")

# Get top 5
top5 = total_counts.most_common(5)

print('__RESULT__:')
print(json.dumps({'top5': top5, 'matched': matched, 'total': len(all_reviews)}))"}
